/****** Object:  StoredProcedure [dbo].[GetAllEmployees]    Script Date: 13-02-2026 2.51.59 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[GetAllEmployees]
(
    @PageNumber INT,
    @PageSize INT,
    @Search NVARCHAR(100) = NULL
)
AS
BEGIN
    SET NOCOUNT ON;

    -- Store filtered results in temp table
    SELECT
        EmployeeId,
        Name,
        Designation,
        Address,
        Department,
        JoiningDate,
        SkillSet,
        Username,
        Role,
        Status
    INTO #FilteredEmployees
    FROM Employees
    WHERE Role <> 'Admin'
    AND
    (
        @Search IS NULL
        OR @Search = ''
        OR CAST(EmployeeId AS VARCHAR(20)) LIKE '%' + @Search + '%'
        OR Name LIKE '%' + @Search + '%'
        OR Designation LIKE '%' + @Search + '%'
        OR Department LIKE '%' + @Search + '%'
        OR CONVERT(VARCHAR(10), JoiningDate, 23) LIKE '%' + @Search + '%'
    );

    -- Return paginated result
    SELECT *
    FROM #FilteredEmployees
    ORDER BY EmployeeId
    OFFSET (@PageNumber - 1) * @PageSize ROWS
    FETCH NEXT @PageSize ROWS ONLY;

    -- Return total count (filtered)
    SELECT COUNT(*) AS TotalCount
    FROM #FilteredEmployees;

END;
GO
/****** Object:  StoredProcedure [dbo].[GetEmployeeById]    Script Date: 13-02-2026 2.51.59 PM ******/
