CREATE PROCEDURE [dbo].[GetEmployeeById]
(
    @EmployeeId INT
)
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        EmployeeId,
        Name,
        Designation,
        Address,
        Department,
        JoiningDate,
        SkillSet,
        Username,
        Role,
        Status,
        CreatedBy,
        CreatedAt,
        ModifiedBy,
        ModifiedAt,
        ProfilePhoto
    FROM Employees
    WHERE EmployeeId = @EmployeeId
      AND Status = 'Active';
END;
