/****** Object:  StoredProcedure [dbo].[RegisterEmployee]    Script Date: 13-02-2026 2.51.59 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[RegisterEmployee]
(
@Name varchar(50),
@Designation varchar(50),
@Address VARCHAR(100),
@Department VARCHAR(50),
@JoiningDate DATE,
@SkillSet VARCHAR(MAX),

@Username VARCHAR(50),
@PasswordHash VARCHAR(255),

@Role VARCHAR(20),
@CreatedBy VARCHAR(50),
@ProfilePhoto VARBINARY(MAX) = NULL
)

as
begin
set nocount on;

 IF EXISTS (SELECT 1 FROM Employees WHERE Username = @Username)
    BEGIN
        RAISERROR ('Username already exists', 16, 1);
        RETURN;
    END;

    begin try
 insert into Employees
 (
	Name,
    Designation,
    Address,
    Department,
    JoiningDate,
    SkillSet,
    Username,
    PasswordHash,
    Role,
    Status,
    CreatedBy,
    ProfilePhoto

 )
 values
 (
        @Name,
        @Designation,
        @Address,
        @Department,
        @JoiningDate,
        @SkillSet,
        @Username,
        @PasswordHash,
        @Role,
        'Active',
        @CreatedBy,
        @ProfilePhoto
 );
 end try
 begin catch
 throw;
 end catch
 end;
