/****** Object:  StoredProcedure [dbo].[SoftDeleteEmployee]    Script Date: 13-02-2026 2.51.59 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[SoftDeleteEmployee]
(
    @EmployeeId INT,
    @ModifiedBy VARCHAR(50)
)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        UPDATE Employees
        SET
            Status = 'Inactive',
            ModifiedBy = @ModifiedBy,
            ModifiedAt = GETDATE()
        WHERE EmployeeId = @EmployeeId
          AND Status = 'Active';

        IF @@ROWCOUNT = 0
            RAISERROR ('Employee already inactive or not found', 16, 1);
    END TRY
    BEGIN CATCH
        THROW;
    END CATCH
END;
GO
