CREATE PROCEDURE [dbo].[UpdateEmployeeByAdmin]
(
    @EmployeeId INT,
    @Name VARCHAR(50),
    @Designation VARCHAR(50),
    @Address VARCHAR(100),
    @Department VARCHAR(50),
    @JoiningDate DATE,
    @SkillSet VARCHAR(MAX),
    @Role VARCHAR(20),
    @Status VARCHAR(20),
    @ModifiedBy VARCHAR(50)
)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        UPDATE Employees
        SET
            Name = @Name,
            Designation = @Designation,
            Address = @Address,
            Department = @Department,
            JoiningDate = @JoiningDate,
            SkillSet = @SkillSet,
            Role = @Role,
            Status = @Status,
            ModifiedBy = @ModifiedBy,
            ModifiedAt = GETDATE()
        WHERE EmployeeId = @EmployeeId;

        IF @@ROWCOUNT = 0
            RAISERROR ('Employee not found', 16, 1);
    END TRY
    BEGIN CATCH
        THROW;
    END CATCH
END;

