CREATE PROCEDURE [dbo].[UpdateEmployeePhoto]
(
    @EmployeeId INT,
    @ProfilePhoto VARBINARY(MAX)
)
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE Employees
    SET ProfilePhoto = @ProfilePhoto,
        ModifiedAt = GETDATE()
    WHERE EmployeeId = @EmployeeId;
END;
