CREATE PROCEDURE [dbo].[UpdateEmployeeProfile]
(
    @EmployeeId INT,
    @Name VARCHAR(50),
    @Designation VARCHAR(50),
    @Address VARCHAR(100),
    @Department VARCHAR(50),
    @SkillSet VARCHAR(MAX),
    @ModifiedBy VARCHAR(50)
)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        UPDATE Employees
        SET
            Name = @Name,
            Designation = @Designation,
            Address = @Address,
            Department = @Department,
            SkillSet = @SkillSet,
            ModifiedBy = @ModifiedBy,
            ModifiedAt = GETDATE()
        WHERE EmployeeId = @EmployeeId
          AND Status = 'Active';

        IF @@ROWCOUNT = 0
            RAISERROR ('Employee not found or inactive', 16, 1);
    END TRY
    BEGIN CATCH
        THROW;
    END CATCH
END;
