CREATE PROCEDURE [dbo].[ValidateLogin]
(
    @Username VARCHAR(50)
)
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        EmployeeId,
        Username,
        PasswordHash,
        Role,
        Status
    FROM Employees
    WHERE Username = @Username;
END;
